'use client';

import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { User, LogIn, ChevronDown, Settings, LogOut, Bookmark } from 'lucide-react';
import { useState, useRef, useEffect } from 'react';
import { useAuthStore } from '@/store/authStore';

export function ProfileButton() {
  const { user, signOut } = useAuthStore();
  const router = useRouter();
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  // 바깥 클릭 닫기
  useEffect(() => {
    function handle(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false);
    }
    document.addEventListener('mousedown', handle);
    return () => document.removeEventListener('mousedown', handle);
  }, []);

  async function handleSignOut() {
    setOpen(false);
    await signOut();
    router.push('/');
    router.refresh();
  }

  // 비로그인
  if (!user) {
    return (
      <Link
        href="/login"
        className="flex items-center gap-1.5 px-3 py-1.5 bg-brand-500 hover:bg-brand-400 text-white rounded-lg text-sm font-medium transition-colors"
      >
        <LogIn className="w-3.5 h-3.5" />
        로그인
      </Link>
    );
  }

  const displayName = user.user_metadata?.username ?? user.email?.split('@')[0] ?? '유저';
  const initial = displayName[0].toUpperCase();

  // 로그인 상태 — 아바타 + 드롭다운
  return (
    <div ref={ref} className="relative">
      <button
        onClick={() => setOpen(!open)}
        className="flex items-center gap-2 px-2 py-1.5 rounded-lg hover:bg-surface-raised transition-colors"
      >
        <div className="w-7 h-7 rounded-full bg-brand-500/20 border border-brand-500/30 flex items-center justify-center text-xs font-bold text-brand-400 shrink-0">
          {initial}
        </div>
        <span className="text-sm text-zinc-300 hidden sm:block max-w-[80px] truncate">
          {displayName}
        </span>
        <ChevronDown className={`w-3.5 h-3.5 text-zinc-500 transition-transform ${open ? 'rotate-180' : ''}`} />
      </button>

      {/* 드롭다운 */}
      {open && (
        <div className="absolute right-0 top-full mt-2 w-52 bg-surface-overlay border border-surface-border rounded-xl shadow-2xl shadow-black/40 overflow-hidden z-50">
          {/* 유저 정보 */}
          <div className="px-4 py-3 border-b border-surface-border">
            <p className="text-sm font-semibold text-white truncate">{displayName}</p>
            <p className="text-xs text-zinc-500 truncate">{user.email}</p>
          </div>

          <div className="p-1.5">
            <Link
              href="/profile"
              onClick={() => setOpen(false)}
              className="flex items-center gap-2.5 px-3 py-2 rounded-lg text-sm text-zinc-300 hover:text-white hover:bg-surface-raised transition-colors"
            >
              <User className="w-4 h-4 shrink-0" />
              프로필
            </Link>
            <Link
              href="/profile?tab=wishlist"
              onClick={() => setOpen(false)}
              className="flex items-center gap-2.5 px-3 py-2 rounded-lg text-sm text-zinc-300 hover:text-white hover:bg-surface-raised transition-colors"
            >
              <Bookmark className="w-4 h-4 shrink-0" />
              관심 목록
            </Link>
            <Link
              href="/settings"
              onClick={() => setOpen(false)}
              className="flex items-center gap-2.5 px-3 py-2 rounded-lg text-sm text-zinc-300 hover:text-white hover:bg-surface-raised transition-colors"
            >
              <Settings className="w-4 h-4 shrink-0" />
              설정
            </Link>
          </div>

          <div className="p-1.5 border-t border-surface-border">
            <button
              onClick={handleSignOut}
              className="w-full flex items-center gap-2.5 px-3 py-2 rounded-lg text-sm text-brand-400 hover:bg-brand-500/10 transition-colors"
            >
              <LogOut className="w-4 h-4 shrink-0" />
              로그아웃
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
